<?php################################## Mod Joe. 13.04.2013 ###################################// Загружаем файл конфига, ВАЖНЫЙ.include ($_SERVER['DOCUMENT_ROOT'].'/configs/config.php');// Подключаемся к SQL базе$db = new MySQL(SQL_USER, SQL_PASS, SQL_BASE);// Подключаем класс обработки входящих данных$http = new Jhttp;############################## $pers = $db->sqla('SELECT * FROM `users` WHERE `uid` = '.intval($http->_cookie('uid')).' and `pass` = "'.$http->_cookie('hashcode').'" and `block`="" and `location` = "lavka";', __FILE__,__LINE__,__FUNCTION__,__CLASS__);if ( !$pers ) {echo 'NO@no_auth'; exit;}include (ROOT.'/inc/func.php');include (ROOT.'/inc/func2.php');if (isset($http->get["buy"]) and $http->get["kolvo"]>0 and $http->get["kolvo"]<100) {	$v = $db->sqla("SELECT price,q_s,where_buy,name,id,max_durability FROM `weapons` WHERE `id`='".$http->get["buy"]."' ;");	$kolvo = intval($http->get["kolvo"]);	if ( $kolvo > $v['q_s'] ) $kolvo = $v['q_s'];	if ( $v["where_buy"]==0 and $v["q_s"]>0 )	{		if ($pers["money"]<($v["price"]*$kolvo))  echo "NO@Недостаточно деняг"; 		else 		{			for ($i=1;$i<=$kolvo;$i++) insert_wp($v["id"],$pers["uid"],$v["max_durability"],0,$pers["user"]);			$pers['money']-= $v["price"]*$kolvo;			set_vars("money=money-".($v["price"]*$kolvo),$pers["uid"]);			$db->sql("UPDATE `weapons` SET `q_s`=q_s - ".$kolvo." WHERE `id`='".$v["id"]."'");			echo 'OK@'.$v['name'].'@'.$v['price'].'@'.$kolvo;		}	}}?>